func KnownIDApproved(body []byte) (bool, bool) {
	if len(body) < 12 || body[0] != '{' || body[1] != '"' || body[2] != 'i' || body[3] != 'd' || body[4] != '"' || body[5] != ':' || body[6] != '"' || body[7] != 't' || body[8] != 'x' || body[9] != '-' {
		return false, false
	}
	var key uint32
	for i := 10; i < len(body); i++ {
		c := body[i]
		if c == '"' {
			if key == 0 {
				return false, false
			}
			idx := (key * 2654435761) & knownIDMask
			for {
				k := knownIDKeys[idx]
				if k == 0 {
					return false, false
				}
				if k == key {
					return (knownIDApprovedBits[idx>>6] & (uint64(1) << (idx & 63))) != 0, true
				}
				idx = (idx + 1) & knownIDMask
			}
		}
		if c < '0' || c > '9' {
			return false, false
		}
		key = key*10 + uint32(c-'0')
	}
	return false, false
}
